#include <cstdio>
#include <omp.h>

#define N 512

void floydWarshall(int dist[N][N]) {
    int i, j, k;

    for (k = 0; k < N; k++) {
        #pragma omp parallel for private(i, j) shared(dist, k) schedule(static)
        for (i = 0; i < N; i++) {
            for (j = 0; j < N; j++) {
                int new_dist = dist[i][k] + dist[k][j];
                if (new_dist < dist[i][j]) {
                    dist[i][j] = new_dist;
                }
            }
        }
    }
}

int main() {
    static int dist[N][N];

    // Initialize the distance matrix
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            if (i == j)
                dist[i][j] = 0;
            else
                dist[i][j] = 99999;
        }
    }

    // Example: Add some edges for testing
    dist[0][1] = 3;
    dist[0][2] = 8;
    dist[0][4] = -4;
    dist[1][3] = 1;
    dist[1][4] = 7;
    dist[2][1] = 4;
    dist[3][0] = 2;
    dist[3][2] = -5;
    dist[4][3] = 6;

    floydWarshall(dist);

    // Print the shortest distance matrix
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            if (dist[i][j] == 99999)
                printf("%7s ", "INF");
            else
                printf("%7d ", dist[i][j]);
        }
        printf("\n");
    }

    return 0;
}
